import com.pinterest.ktlint.test.KtLintAssertThat
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import org.junit.jupiter.api.Test

/**
 * Test for the reported issue: Fix indent when property value is wrapped to next line
 * 
 * When a property value is wrapped to the next line, it should be indented properly
 * with one additional level of indentation relative to the property declaration.
 */
class PropertyWrappingRuleIssueTest {
    private val propertyWrappingRuleAssertThat = KtLintAssertThat.assertThatRule { PropertyWrappingRule() }

    @Test
    fun `Given a property with a call expression that does not fit on one line, wrap it with correct indentation`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                                                           $EOL_CHAR
            class Test {
                private val deferredMessageQueueSubscription = DeferredMessageQueueSubscription(uri = ServiceBusUri("deferredQueueTestUri"))
            }
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                                                                           $EOL_CHAR
            class Test {
                private val deferredMessageQueueSubscription =
                    DeferredMessageQueueSubscription(uri = ServiceBusUri("deferredQueueTestUri"))
            }
            """.trimIndent()
        propertyWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { IndentationRule() }
            .hasLintViolation(3, 56, "Missing newline before \"DeferredMessageQueueSubscription(uri = ServiceBusUri(\"deferredQueueTestUri\"))\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a property with call expression that needs wrapping, the wrapped value should be indented correctly`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                $EOL_CHAR
            val myVariable = MyConstructor(param1, param2)
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                $EOL_CHAR
            val myVariable =
                MyConstructor(param1, param2)
            """.trimIndent()
        propertyWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { IndentationRule() }
            .hasLintViolation(2, 18, "Missing newline before \"MyConstructor(param1, param2)\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a nested property with call expression that needs wrapping, the wrapped value should maintain proper indentation level`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER            $EOL_CHAR
            class Outer {
                val inner = InnerClass(param1, param2)
            }
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER            $EOL_CHAR
            class Outer {
                val inner =
                    InnerClass(param1, param2)
            }
            """.trimIndent()
        propertyWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { IndentationRule() }
            .hasLintViolation(3, 17, "Missing newline before \"InnerClass(param1, param2)\"")
            .isFormattedAs(formattedCode)
    }
}
"}

